package problems;

public class ContainerWithMostWater {

    public static void main(String[] args) {

        int[] heights = {1, 8, 6, 2, 5, 4, 8, 3, 7};
        System.out.println("Max water container can hold is " + maxWater(heights));
    }

    static{ // Static Block to warm up the JVM
        for(int i=0;i<60;i++){
            maxWater(new int[]{0,0});
        }
    }

    public static int maxWater(int[] height) {

        //  You are given an integer array height of length n. 
        // There are n vertical lines drawn such that the two endpoints of the ith line are (i, 0) and (i, height[i]).
        // Find two lines that together with the x-axis form a container, such that the container contains the most water.
        // Return the maximum amount of water a container can store.
        // Notice that you may not slant the container.
        // Example 1:
        // Input: height = [1,8,6,2,5,4,8,3,7]
        // Output: 49
        // Explanation: The above vertical lines are represented by array [1,8,6,2,5,4,8,3,7]. In this case, the max area of water (blue section) the container can contain is 49.
        // Example 2:
        // Input: height = [1,1]
        // Output: 1
        int max = 0, left = 0, right = height.length - 1;

        while (left < right) {
            int width = right - left;
            int area = Math.min(height[right], height[left]) * width;
            max = Math.max(max, area);

            if (height[left] <= height[right]) {
                left++;
            } else {
                right--;
            }
        }


        System.gc();  // Cleaning the resources 
        return max;
    }
}
